private boolean toStringEquals(Matcher m, Object arg) {
    if (m == null || arg == null) return false;
    if (!m.getClass().equals(arg.getClass())) return false;
    return StringDescription.toString(m).equals(arg.toString());
}

private boolean toStringEquals(Matcher m, Object arg) {
    if (m == null || arg == null) {
        return false;
    }
    if (!(arg instanceof Matcher)) {
        return false;
    }
    return StringDescription.toString(m).equals(StringDescription.toString((Matcher) arg));
}
